class SparseTable {
    constructor(arr) {
        this.n = arr.length;
        this.log = new Array(this.n + 1).fill(0);
        this.st = [];
        this.build(arr);
    }

    build(arr) {
        for (let i = 0; (1 << i) <= this.n; i++) {
            this.st.push(new Array(this.n).fill(-Infinity));
        }

        for (let i = 0; i < this.n; i++) {
            this.st[0][i] = arr[i];
        }

        for (let j = 1; (1 << j) <= this.n; j++) {
            for (let i = 0; i + (1 << j) <= this.n; i++) {
                this.st[j][i] = Math.max(this.st[j-1][i], this.st[j-1][i + (1 << (j-1))]);
            }
        }

        for (let i = 2; i <= this.n; i++) {
            this.log[i] = this.log[i >> 1] + 1;
        }
    }

    query(l, r) {
        if (l > r) {
            return -Infinity;
        }
        let j = this.log[r - l + 1];
        return Math.max(this.st[j][l], this.st[j][r - (1 << j) + 1]);
    }
}

